// Shared variables
volatile bool lock = false;
volatile bool key = false;

// Atomic swap function (hardware instruction)
void Swap(bool *a, bool *b) {
    bool temp = *a;
    *a = *b;
    *b = temp;
    // This must be atomic - implemented in hardware
}

// Process entry
void processEntry() {
    do {
        key = true;
        Swap(&key, &lock);  // Atomically swap key with lock
    } while (key);  // If key is true after swap, lock was held

    // Critical section begins
    // ... shared resource access ...
}

// Process exit
void processExit() {
    lock = false;  // Release lock
    // Remainder section continues
}

import java.util.concurrent.atomic.AtomicBoolean;

public class Spinlock {
    // AtomicBoolean uses compare-and-swap internally
    private AtomicBoolean lock = new AtomicBoolean(false);

    public void lock() {
        // Spin until we acquire the lock
        while (!lock.compareAndSet(false, true)) {
            // Lock was already held, try again
            Thread.yield();  // Optionally yield to reduce CPU usage
        }
    }

    public void unlock() {
        lock.set(false);  // Release the lock
    }
}

// Usage in critical section
public class SharedResource {
    private Spinlock spinlock = new Spinlock();
    private int sharedData = 0;

    public void criticalSectionMethod() {
        spinlock.lock();
        try {
            // Critical section - access sharedData
            sharedData++;
            System.out.println("Updated: " + sharedData);
        } finally {
            spinlock.unlock();  // Always unlock in finally block
        }
    }
}
